/**
 * @param {number[]} nums
 * @param {number} target
 * @return {number}
 */
var countMajoritySubarrays = function(nums, target) {
    const n = nums.length;
    const dp = new Array(n * 2 + 1).fill(0);
    dp[n] = 1;
    let pos = n;
    let sum = 0;
    let res = 0;

    for (let i = 0; i < n; i++) {
        if (nums[i] === target) {
            sum += dp[pos];
            pos++;
        } else {
            pos--;
            sum -= dp[pos];
        }

        dp[pos]++;
        res += sum;
    }

    return res;
};
